import { useState } from "react";
import "./forgot.css";

function Forgot() {
    let [emailinput, changeemailinput] = useState("");

    async function func1() {
        await fetch("http://localhost:5000/forgotpassword", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({ email: emailinput })
        });

        alert("If an account with the provided email exists, a password reset link has been sent.");
    }

    return (
        <div className="forgot-container">
            <div className="forgot-card">
                <h1>Forgot password?</h1>
                <p>Enter your email and we’ll send you a reset link.</p>

                <input
                    value={emailinput}
                    onChange={(e) => changeemailinput(e.target.value)}
                    type="email"
                    placeholder="Email"
                />

                <button onClick={func1}>Submit</button>
            </div>
        </div>
    );
}

export default Forgot;
